138	fn main() -> ExitCode {
139	    CompleteEnv::with_factory(Cli::command).complete();
140	    let cli = Cli::parse();
141	
142	    let log_path = cli.log.as_ref().map(|p| p.to_string_lossy().to_string());
143	    logging::CliLogger::init(cli.verbose, log_path.as_deref());
144	
145	    // Surface any failure markers left by previous detached finalize children,
146	    // unless we ARE a detached child (the `--exec` re-entry). A detached child
147	    // shouldn't consume markers meant for the user's next interactive run.
148	    let is_detached_exec = matches!(
149	        cli.command,
150	        Commands::Finalize(ref f) if f.exec
151	    );
152	    if !is_detached_exec {
153	        finalize::surface_previous_failures();
154	    }
155	
156	    match cli.command {
157	        Commands::Chid(chid_args) => run_command(chid::chid(&chid_args)),
158	        Commands::Desc(desc_args) => run_command(desc::desc(&desc_args)),
159	        Commands::List(list_args) => run_command(list::list(&list_args)),
160	        Commands::Show(show_args) => run_command(show::show(&show_args)),
161	        Commands::ValidateDesc(validate_desc_args) => {
