/// Banner string shown at the top of every `--help` output across
/// the binary and its subcommands, plus emitted as the first line
/// of normal command runs. Built from `Cargo.toml`'s name + version
/// at compile time so it stays in sync with the bumped version.
const BANNER: &str = concat!(env!("CARGO_PKG_NAME"), " ", env!("CARGO_PKG_VERSION"));

/// Build the full clap command tree with `BANNER` set as
/// `before_help` on the top level and every (transitively) nested
/// subcommand. Walks via `mut_subcommand` so individual subcommand
/// `#[command(long_about = ...)]` blocks don't have to repeat the
/// banner text.
fn cli_with_banner() -> clap::Command {
    fn add(mut cmd: clap::Command) -> clap::Command {
        cmd = cmd.before_help(BANNER);
        let names: Vec<String> = cmd
            .get_subcommands()
            .map(|c| c.get_name().to_string())
            .collect();
        for name in names {
            cmd = cmd.mut_subcommand(name, add);
        }
        cmd
    }
    add(Cli::command())
}

